    if (existsSync(this.gen3StoragePath)) {
      try {
        const data = readFileSync(this.gen3StoragePath, "utf-8");
        return JSON.parse(data);
      } catch {
        // Invalid state, reset
      }
    }
    return {
      generation: 3,
      modifications: [],
      lastModified: new Date().toISOString(),
      selfAwarenessScore: 0.0
    };
